40	#[test]
41	fn insert() {
42	    let insert = [0, 4, 2, 12, 8, 7, 11, 5];
43	    let not_present = [1, 3, 6, 9, 10];
44	    let s = SkipMap::new();
45	
46	    for &x in &insert {
47	        s.insert(x, x * 10);
48	        assert_eq!(*s.get(&x).unwrap().value(), x * 10);
49	    }
