56	#[test]
57	fn compare_and_insert() {
58	    let insert = [0, 4, 2, 12, 8, 7, 11, 5];
59	    let not_present = [1, 3, 6, 9, 10];
60	    let s = SkipMap::new();
61	
62	    for &x in &insert {
63	        s.insert(x, x * 10);
64	    }
65	
66	    for &x in &insert {
67	        let value = x * 5;
68	        let old_value = *s.get(&x).unwrap().value();
69	        s.compare_insert(x, value, |x| x < &value);
70	        assert_eq!(*s.get(&x).unwrap().value(), old_value);
71	    }
72	
73	    for &x in &insert {
74	        let value = x * 15;
75	        s.compare_insert(x, value, |x| x < &value);
76	        assert_eq!(*s.get(&x).unwrap().value(), value);
77	    }
78	
79	    for &x in &not_present {
80	        assert!(s.get(&x).is_none());
81	    }
82	}
