85	fn compare_insert_with_absent_key() {
86	    let insert = [0, 4, 2, 12, 8, 7, 11, 5];
87	    let s = SkipMap::new();
88	
89	    // The closure will not be called if the key is not present,
90	    // so the key-value will be inserted into the map
91	    for &x in &insert {
92	        let value = x * 15;
