154	fn concurrent_compare_and_insert() {
155	    let set: SkipMap<i32, i32> = SkipMap::new();
156	    let set = std::sync::Arc::new(set);
157	    let len = 100;
158	    let mut handlers = Vec::with_capacity(len as usize);
159	    for i in 0..len {
