#[test]
fn concurrent_insert_get_same_key() {
    let map: Arc<SkipMap<u32, ()>> = Arc::new(SkipMap::new());
    let len = if cfg!(miri) { 100 } else { 10_000 };
    let key = 0;
    map.insert(0, ());

    let getter = map.clone();
    let handle = std::thread::spawn(move || {
        for _ in 0..len {
            map.insert(0, ());
        }
    });
    for _ in 0..len {
        assert!(getter.get(&key).is_some());
